// Toplam metin sayısını hesaplayan yardımcı fonksiyon
function getTotalTextCount() {
    let total = 0;
    for (let category in metinlerDB) {
        if (metinlerDB[category].groups) {
            // Eğer CATEGORIES yapısındaki gibi groups varsa
            // Ama metinlerDB'de metinler kategori -> grup -> array şeklinde
        }
        for (let group in metinlerDB[category]) {
            if (Array.isArray(metinlerDB[category][group])) {
                total += metinlerDB[category][group].length;
            }
        }
    }
    return total;
}

if (typeof window !== 'undefined') {
    window.metinlerDB = metinlerDB;
    window.getTotalTextCount = getTotalTextCount;
}
